def _common_css():
    """Return common CSS shared by all pages."""
    return '''* { margin:0; padding:0; box-sizing:border-box; }
:root {
  --bg: #0c0b09;
  --surface: #141210;
  --surface2: #1a1816;
  --border: #2a2520;
  --border-light: #3a3530;
  --gold: #c9a96e;
  --gold-dim: #8a7e6b;
  --text: #e0d5c1;
  --text-dim: #8a7e6b;
  --text-faint: #5a5040;
  --accent: #a08050;
  --red: #c45a5a;
}
body { background:var(--bg); color:var(--text); font-family:'Source Sans 3',sans-serif; font-weight:400; line-height:1.6; }

/* LANGUAGE BAR */
.lang-bar { position:sticky; top:0; z-index:200; background:rgba(12,11,9,.98); backdrop-filter:blur(16px); padding:8px 20px; border-bottom:1px solid var(--border); display:flex; gap:0; justify-content:center; align-items:center; }
.lang-bar .lang-label { font-size:0.7em; color:var(--text-faint); text-transform:uppercase; letter-spacing:2px; margin-right:12px; font-weight:500; }
.lang-btn { padding:6px 14px; background:transparent; border:1px solid transparent; cursor:pointer; font-size:0.82em; font-family:'Source Sans 3',sans-serif; color:var(--text-dim); transition:all .2s; border-radius:3px; font-weight:500; }
.lang-btn:hover { color:var(--gold); border-color:var(--border); }
.lang-btn.active { color:var(--gold); border-color:var(--gold); background:rgba(201,169,110,.08); font-weight:600; }
[data-lang] { display:none; }
[data-lang="pl"] { display:revert; }
body.lang-js [data-lang] { display:none; }
body.lang-js [data-lang].lang-visible { display:revert; }

/* PAGE NAV */
.page-nav { display:flex; justify-content:center; gap:0; background:var(--surface); border-bottom:1px solid var(--border); padding:0; }
.page-nav-link { padding:14px 28px; color:var(--text-dim); text-decoration:none; font-size:0.9em; font-weight:500; border-bottom:3px solid transparent; transition:all .2s; }
.page-nav-link:hover { color:var(--gold); background:var(--surface2); }
.page-nav-link.active { color:var(--gold); border-bottom-color:var(--gold); font-weight:600; }

/* HEADER */
.header { text-align:center; padding:60px 20px 30px; border-bottom:1px solid var(--border); }
.header h1 { font-family:'Playfair Display',serif; font-size:2.4em; color:var(--gold); letter-spacing:2px; margin-bottom:8px; }
.header .subtitle { color:var(--text-dim); font-size:1.1em; font-weight:300; }

/* PHOTO ARCHIVE GRID */
.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
    gap: 12px;
    padding: 20px;
    max-width: 1400px;
    margin: 0 auto;
}
.photo-card {
    border: 1px solid var(--border);
    border-radius: 8px;
    overflow: hidden;
    cursor: pointer;
    transition: transform 0.2s, box-shadow 0.2s;
    background: var(--surface);
}
.photo-card:hover {
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(0,0,0,.4);
    border-color: var(--accent);
}
.photo-card img {
    width: 100%;
    height: 140px;
    object-fit: cover;
}
.photo-card .card-info {
    padding: 8px;
    font-size: 12px;
}
.photo-card .card-sygn {
    font-family: 'JetBrains Mono', monospace;
    font-weight: bold;
    color: var(--gold);
    font-size: 11px;
}
.photo-card .card-title {
    color: var(--text-dim);
    margin-top: 4px;
    line-height: 1.3;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

/* FILTER BAR */
.filter-bar {
    display: flex;
    gap: 12px;
    padding: 15px 20px;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 8px;
    margin: 20px auto 15px;
    max-width: 1400px;
    flex-wrap: wrap;
    align-items: center;
}
.filter-bar select, .filter-bar input {
    padding: 8px 12px;
    border: 1px solid var(--border);
    border-radius: 4px;
    font-size: 14px;
    background: var(--surface2);
    color: var(--text);
    font-family: 'Source Sans 3', sans-serif;
}
.filter-bar select:focus, .filter-bar input:focus {
    outline: none;
    border-color: var(--gold);
}
.photo-count {
    margin-left: auto;
    color: var(--text-faint);
    font-size: 14px;
}

/* LIGHTBOX */
.lightbox { display:none; position:fixed; top:0; left:0; width:100%; height:100%; background:rgba(0,0,0,.95); z-index:9999; justify-content:center; align-items:center; flex-direction:column; }
.lightbox.active { display:flex; }
.lightbox img { max-width:90%; max-height:80vh; object-fit:contain; transition:transform .3s; cursor:grab; }
.lightbox img.notransition { transition:none; }
.lb-close { position:absolute; top:20px; right:30px; color:#fff; font-size:40px; cursor:pointer; z-index:10001; }
.lb-title { color:var(--text-dim); margin-top:12px; font-size:0.9em; text-align:center; max-width:80%; }
.lb-controls { display:flex; gap:8px; margin-bottom:12px; z-index:10001; }
.lb-btn { background:rgba(255,255,255,.1); border:1px solid rgba(255,255,255,.2); color:#fff; width:40px; height:40px; border-radius:50%; cursor:pointer; font-size:1.2em; display:flex; align-items:center; justify-content:center; transition:background .2s; }
.lb-btn:hover { background:rgba(255,255,255,.25); }
.lb-zoom-info { position:absolute; top:20px; left:50%; transform:translateX(-50%); background:rgba(0,0,0,.7); color:var(--gold); padding:4px 12px; border-radius:4px; font-size:0.85em; opacity:0; transition:opacity .3s; z-index:10002; }
.lb-zoom-info.visible { opacity:1; }

/* FOOTER NAV BUTTONS */
.footer-nav { display:flex; justify-content:center; gap:20px; padding:50px 20px 30px; max-width:1100px; margin:0 auto; flex-wrap:wrap; }
.footer-btn { display:flex; flex-direction:column; align-items:center; text-decoration:none; padding:28px 24px; background:var(--surface); border:1px solid var(--border); border-radius:8px; flex:1; min-width:240px; max-width:340px; transition:all .3s; }
.footer-btn:hover { border-color:var(--gold); transform:translateY(-2px); box-shadow:0 8px 24px rgba(0,0,0,.3); }
.footer-btn-icon { font-size:2.2em; margin-bottom:10px; }
.footer-btn-label { font-family:'Playfair Display',serif; font-size:1.1em; color:var(--gold); font-weight:600; margin-bottom:6px; }
.footer-btn-desc { font-size:0.8em; color:var(--text-dim); text-align:center; line-height:1.4; }

/* FOOTER */
.footer { text-align:center; padding:30px 20px 50px; color:var(--text-faint); font-size:0.78em; border-top:1px solid var(--border); line-height:1.8; }
.footer a { color:var(--gold-dim); text-decoration:none; }
.footer a:hover { color:var(--gold); }

/* SERIES */
.series { max-width:1400px; margin:0 auto; padding:50px 20px 30px; }
.series-header { margin-bottom:30px; padding-bottom:16px; border-bottom:1px solid var(--border); }
.series-num { font-family:'JetBrains Mono',monospace; font-size:0.75em; color:var(--gold); letter-spacing:2px; margin-bottom:4px; }
.series-title { font-family:'Playfair Display',serif; font-size:1.6em; color:var(--text); font-weight:600; margin-bottom:8px; }
.series-desc { font-size:0.9em; color:var(--text-dim); line-height:1.6; max-width:800px; }
.series-meta { font-size:0.8em; color:var(--text-faint); margin-top:8px; }

/* CARDS GRID */
.cards-grid { display:grid; grid-template-columns:repeat(auto-fill, minmax(380px, 1fr)); gap:20px; }

/* CARD */
.card { background:var(--surface); border:1px solid var(--border); border-radius:4px; overflow:hidden; cursor:pointer; transition:all .3s; }
.card:hover { border-color:var(--accent); transform:translateY(-1px); box-shadow:0 6px 20px rgba(0,0,0,.3); }
.card-img-wrap { height:260px; overflow:hidden; background:#0a0908; display:flex; align-items:center; justify-content:center; border-bottom:1px solid var(--border); }
.card-img-wrap img { max-width:100%; max-height:100%; object-fit:contain; }
.card-body { padding:18px; }
.card-sygn { font-family:'JetBrains Mono',monospace; font-size:0.7em; color:var(--gold); letter-spacing:1px; margin-bottom:6px; }
.card-title { font-family:'Playfair Display',serif; font-size:1.05em; color:var(--text); margin-bottom:8px; line-height:1.35; font-weight:600; }
.card-meta-row { display:flex; justify-content:space-between; align-items:center; margin-bottom:10px; padding-bottom:8px; border-bottom:1px solid var(--border); }
.card-date { font-size:0.85em; color:var(--gold); font-weight:500; }
.card-type { font-size:0.72em; color:var(--text-faint); background:var(--surface2); padding:2px 8px; border-radius:2px; text-transform:uppercase; letter-spacing:1px; }
.card-field { font-size:0.82em; color:var(--text-dim); margin-bottom:6px; line-height:1.5; }
.field-label { color:var(--text-faint); font-weight:500; font-size:0.9em; }
.card-context { color:var(--accent); font-style:italic; }
.card-condition { font-size:0.75em; color:var(--text-faint); margin-top:8px; padding-top:6px; border-top:1px solid var(--border); }
.powiazanie-link { color:var(--gold); text-decoration:none; font-family:'JetBrains Mono',monospace; font-size:0.95em; transition:color .2s; }
.powiazanie-link:hover { color:var(--accent); text-decoration:underline; }
.card.highlight-target { border-color:var(--gold) !important; box-shadow:0 0 20px rgba(201,169,110,.3) !important; transition:all .5s; }

/* NAV */
.nav { position:sticky; top:38px; z-index:100; background:rgba(12,11,9,.95); backdrop-filter:blur(12px); padding:14px 20px; border-bottom:1px solid var(--border); display:flex; flex-wrap:wrap; gap:8px; justify-content:center; }
.nav-link { color:var(--text-dim); text-decoration:none; font-size:0.8em; padding:5px 12px; border:1px solid var(--border); border-radius:3px; transition:all .2s; font-weight:500; }
.nav-link:hover { color:var(--gold); border-color:var(--gold); }

/* TRANSCRIPTION PANELS */
.card-transcription { border-top:1px solid var(--border); margin-top:10px; padding-top:8px; }
.trans-toggle { cursor:pointer; font-size:0.82em; color:var(--gold); font-weight:500; padding:4px 0; user-select:none; }
.trans-toggle:hover { color:var(--accent); }
.trans-content { display:none; padding:10px 0 4px; }
.card-transcription.open .trans-toggle { color:var(--accent); }
.card-transcription.open .trans-content { display:block; }
.trans-meta { display:flex; gap:6px; flex-wrap:wrap; margin-bottom:8px; }
.trans-badge { font-size:0.72em; background:var(--surface2); border:1px solid var(--border); color:var(--text-dim); padding:2px 8px; border-radius:2px; }
.trans-field { font-size:0.8em; color:var(--text-dim); margin-bottom:4px; line-height:1.5; }
.trans-field strong { color:var(--text-faint); }
.trans-text { font-family:'JetBrains Mono',monospace; font-size:0.78em; color:var(--text); background:var(--surface2); padding:12px; border-radius:4px; margin:8px 0; white-space:pre-wrap; line-height:1.6; max-height:300px; overflow-y:auto; }
.trans-details { font-size:0.78em; color:var(--text-dim); margin-top:6px; }
.trans-details strong { color:var(--text-faint); }
.trans-detail-list { list-style:none; padding:0; margin:4px 0 8px; }
.trans-detail-list li { padding:2px 0; border-bottom:1px solid rgba(255,255,255,.03); }
.trans-detail-list li::before { content:'· '; color:var(--gold); }

@media (max-width:600px) {
  .photo-grid { grid-template-columns: repeat(auto-fill, minmax(140px, 1fr)); gap: 8px; padding: 10px; }
  .photo-card img { height: 110px; }
  .filter-bar { padding: 10px; gap: 8px; }
  .filter-bar select, .filter-bar input { font-size: 13px; padding: 6px 10px; }
  .page-nav-link { padding:10px 14px; font-size:0.82em; }
  .cards-grid { grid-template-columns:1fr; }
  .series-title { font-size:1.3em; }
}'''


def _lang_bar_html():
    """Return the language switcher bar HTML."""
    return '''<div class="lang-bar" id="lang-bar">
  <span class="lang-label">Język / Language</span>
  <button class="lang-btn active" onclick="switchLang('pl', this)">PL</button>
  <button class="lang-btn" onclick="switchLang('en', this)">EN</button>
  <button class="lang-btn" onclick="switchLang('pt', this)">PT</button>
  <button class="lang-btn" onclick="switchLang('de', this)">DE</button>
  <button class="lang-btn" onclick="switchLang('nl', this)">NL</button>
  <button class="lang-btn" onclick="switchLang('fr', this)">FR</button>
  <button class="lang-btn" onclick="switchLang('yi', this)">YI</button>
</div>'''


def _page_nav_html(active):
    """Return page navigation bar with 7-language labels. active = 'katalog' | 'archiwum' | 'galeria'."""
    labels = {
        'katalog': {
            'pl': 'Katalog', 'en': 'Catalog', 'pt': 'Cat\u00e1logo', 'de': 'Katalog',
            'nl': 'Catalogus', 'fr': 'Catalogue', 'yi': '\u05e7\u05d0\u05b7\u05d8\u05d0\u05b7\u05dc\u05d0\u05b8\u05d2'
        },
        'archiwum': {
            'pl': 'Archiwum', 'en': 'Archive', 'pt': 'Arquivo', 'de': 'Archiv',
            'nl': 'Archief', 'fr': 'Archives', 'yi': '\u05d0\u05b7\u05e8\u05db\u05d9\u05d5\u05d5'
        },
        'galeria': {
            'pl': 'Galeria', 'en': 'Gallery', 'pt': 'Galeria', 'de': 'Galerie',
            'nl': 'Galerij', 'fr': 'Galerie', 'yi': '\u05d2\u05d0\u05b7\u05dc\u05e2\u05e8\u05d9\u05e2'
        },
        'korespondencja': {
            'pl': 'Listy', 'en': 'Letters', 'pt': 'Cartas', 'de': 'Briefe',
            'nl': 'Brieven', 'fr': 'Lettres', 'yi': '\u05d1\u05e8\u05d9\u05d5\u05d5'
        }
    }
    nav_links = ""
    for page, href in [('katalog', 'katalog_gluchowski_v4.html'), ('archiwum', 'archiwum.html'), ('galeria', 'galeria.html'), ('korespondencja', 'korespondencja.html')]:
        cls = ' active' if page == active else ''
        spans = ' '.join('<span data-lang="' + lang + '">' + text + '</span>' for lang, text in labels[page].items())
        nav_links += '  <a href="' + href + '" class="page-nav-link' + cls + '">' + spans + '</a>\n'
    return '<div class="page-nav">\n' + nav_links + '</div>'


def _lightbox_html():
    """Return lightbox HTML."""
    return '''<div class="lightbox" id="lightbox" onclick="handleLightboxClick(event)">
  <button class="lb-close" onclick="closeLightbox()" aria-label="Zamknij">&times;</button>
  <div class="lb-zoom-info" id="lb-zoom-info"></div>
  <div class="lb-controls">
    <button class="lb-btn" onclick="zoomOut(event)" title="Pomniejsz (-)">&#x2212;</button>
    <button class="lb-btn" onclick="rotateCCW(event)" title="Obrot w lewo (Q)">&#x21BA;</button>
    <button class="lb-btn" onclick="rotateCW(event)" title="Obrot w prawo (E)">&#x21BB;</button>
    <button class="lb-btn" onclick="zoomIn(event)" title="Powieksz (+)">&#x2b;</button>
    <button class="lb-btn" onclick="zoomReset(event)" title="Resetuj (0)" style="font-size:1em;">1:1</button>
  </div>
  <img id="lb-img" src="" alt="">
  <div class="lb-title" id="lb-title"></div>
</div>'''


def _lightbox_js():
    """Return lightbox JavaScript (no script tags)."""
    return '''let currentRotation = 0;
let currentZoom = 1;
let panX = 0, panY = 0;
let isDragging = false, dragStartX = 0, dragStartY = 0, dragStartPanX = 0, dragStartPanY = 0;
let zoomInfoTimeout = null;
let pinchStartDist = 0, pinchStartZoom = 1;

function applyTransform() {
  const img = document.getElementById('lb-img');
  img.style.transform = 'translate(' + panX + 'px,' + panY + 'px) rotate(' + currentRotation + 'deg) scale(' + currentZoom + ')';
}

function showZoomInfo() {
  const el = document.getElementById('lb-zoom-info');
  el.textContent = Math.round(currentZoom * 100) + '%';
  el.classList.add('visible');
  clearTimeout(zoomInfoTimeout);
  zoomInfoTimeout = setTimeout(() => el.classList.remove('visible'), 1200);
}

function openLightbox(src, title) {
  currentRotation = 0; currentZoom = 1; panX = 0; panY = 0;
  const img = document.getElementById('lb-img');
  img.src = src;
  img.alt = title;
  img.className = '';
  applyTransform();
  document.getElementById('lb-title').textContent = title;
  document.getElementById('lightbox').classList.add('active');
  document.body.style.overflow = 'hidden';
}
function closeLightbox() {
  document.getElementById('lightbox').classList.remove('active');
  document.body.style.overflow = '';
}
function rotateCW(e) {
  e && e.stopPropagation();
  currentRotation = (currentRotation + 90) % 360;
  applyTransform();
}
function rotateCCW(e) {
  e && e.stopPropagation();
  currentRotation = (currentRotation - 90 + 360) % 360;
  applyTransform();
}
function zoomIn(e) {
  e && e.stopPropagation();
  currentZoom = Math.min(currentZoom * 1.3, 8);
  applyTransform(); showZoomInfo();
}
function zoomOut(e) {
  e && e.stopPropagation();
  currentZoom = Math.max(currentZoom / 1.3, 0.2);
  applyTransform(); showZoomInfo();
}
function zoomReset(e) {
  e && e.stopPropagation();
  currentZoom = 1; panX = 0; panY = 0; currentRotation = 0;
  applyTransform(); showZoomInfo();
}
function handleLightboxClick(event) {
  if (event.target.id === 'lightbox') closeLightbox();
}

/* Mouse wheel zoom */
document.getElementById('lightbox').addEventListener('wheel', function(e) {
  e.preventDefault();
  if (e.deltaY < 0) { currentZoom = Math.min(currentZoom * 1.15, 8); }
  else { currentZoom = Math.max(currentZoom / 1.15, 0.2); }
  applyTransform(); showZoomInfo();
}, { passive: false });

/* Mouse drag */
const lbImg = document.getElementById('lb-img');
lbImg.addEventListener('mousedown', function(e) {
  if (currentZoom <= 1) return;
  isDragging = true;
  dragStartX = e.clientX; dragStartY = e.clientY;
  dragStartPanX = panX; dragStartPanY = panY;
  lbImg.classList.add('notransition');
  e.preventDefault();
});
document.addEventListener('mousemove', function(e) {
  if (!isDragging) return;
  panX = dragStartPanX + (e.clientX - dragStartX);
  panY = dragStartPanY + (e.clientY - dragStartY);
  applyTransform();
});
document.addEventListener('mouseup', function() {
  isDragging = false;
  lbImg.classList.remove('notransition');
});

/* Touch pinch zoom + drag */
document.getElementById('lightbox').addEventListener('touchstart', function(e) {
  if (e.touches.length === 2) {
    const dx = e.touches[0].clientX - e.touches[1].clientX;
    const dy = e.touches[0].clientY - e.touches[1].clientY;
    pinchStartDist = Math.sqrt(dx*dx + dy*dy);
    pinchStartZoom = currentZoom;
    e.preventDefault();
  } else if (e.touches.length === 1 && currentZoom > 1) {
    isDragging = true;
    dragStartX = e.touches[0].clientX; dragStartY = e.touches[0].clientY;
    dragStartPanX = panX; dragStartPanY = panY;
    lbImg.classList.add('notransition');
  }
}, { passive: false });
document.getElementById('lightbox').addEventListener('touchmove', function(e) {
  if (e.touches.length === 2) {
    e.preventDefault();
    const dx = e.touches[0].clientX - e.touches[1].clientX;
    const dy = e.touches[0].clientY - e.touches[1].clientY;
    const dist = Math.sqrt(dx*dx + dy*dy);
    const newZoom = pinchStartZoom * (dist / pinchStartDist);
    currentZoom = Math.max(0.2, Math.min(8, newZoom));
    applyTransform(); showZoomInfo();
  } else if (isDragging && e.touches.length === 1) {
    panX = dragStartPanX + (e.touches[0].clientX - dragStartX);
    panY = dragStartPanY + (e.touches[0].clientY - dragStartY);
    applyTransform();
  }
}, { passive: false });
document.getElementById('lightbox').addEventListener('touchend', () => {
  isDragging = false;
  lbImg.classList.remove('notransition');
});

/* Keyboard */
document.addEventListener('keydown', e => {
  const lb = document.getElementById('lightbox');
  if (!lb.classList.contains('active')) return;
  if(e.key==='Escape') closeLightbox();
  if(e.key==='e' || e.key==='E' || e.key==='ArrowRight') rotateCW();
  if(e.key==='q' || e.key==='Q' || e.key==='ArrowLeft') rotateCCW();
  if(e.key==='+' || e.key==='=') zoomIn();
  if(e.key==='-' || e.key==='_') zoomOut();
  if(e.key==='0') zoomReset();
});'''


def _lang_js():
    """Return language switching JavaScript (no script tags)."""
    return '''function switchLang(lang, btn) {
  document.body.classList.add('lang-js');
  document.querySelectorAll('.lang-btn').forEach(b => b.classList.remove('active'));
  if (btn) btn.classList.add('active');

  /* Show/hide elements with data-lang using group-based fallback */
  const allLanged = document.querySelectorAll('[data-lang]');
  allLanged.forEach(el => el.classList.remove('lang-visible'));

  /* Group by parent */
  const groups = new Map();
  allLanged.forEach(el => {
    const p = el.parentElement;
    if (!groups.has(p)) groups.set(p, []);
    groups.get(p).push(el);
  });
  groups.forEach(siblings => {
    let match = siblings.find(el => el.dataset.lang === lang);
    if (!match) match = siblings.find(el => el.dataset.lang === 'en');
    if (!match) match = siblings.find(el => el.dataset.lang === 'pl');
    if (match) match.classList.add('lang-visible');
  });

  /* Translate field labels on cards */
  const FIELD_LABELS = {
    pl: { opis_fiz:'Opis fizyczny:', tresc:'Treść:', tworca:'Twórca:', jezyk:'Język:', kontekst:'Kontekst:', stan:'Stan:', powiazania:'Powiązania:' },
    en: { opis_fiz:'Physical description:', tresc:'Content:', tworca:'Creator:', jezyk:'Language:', kontekst:'Context:', stan:'Condition:', powiazania:'Related items:' },
    pt: { opis_fiz:'Descrição física:', tresc:'Conteúdo:', tworca:'Autor:', jezyk:'Idioma:', kontekst:'Contexto:', stan:'Estado:', powiazania:'Itens relacionados:' },
    de: { opis_fiz:'Physische Beschreibung:', tresc:'Inhalt:', tworca:'Urheber:', jezyk:'Sprache:', kontekst:'Kontext:', stan:'Zustand:', powiazania:'Verwandte Objekte:' },
    nl: { opis_fiz:'Fysieke beschrijving:', tresc:'Inhoud:', tworca:'Maker:', jezyk:'Taal:', kontekst:'Context:', stan:'Conditie:', powiazania:'Gerelateerde items:' },
    fr: { opis_fiz:'Description physique:', tresc:'Contenu:', tworca:'Créateur:', jezyk:'Langue:', kontekst:'Contexte:', stan:'État:', powiazania:'Objets liés:' },
    yi: { opis_fiz:'פֿיזישע באַשרײַבונג:', tresc:'אינהאַלט:', tworca:'שעפֿער:', jezyk:'שפּראַך:', kontekst:'קאָנטעקסט:', stan:'צושטאַנד:', powiazania:'פֿאַרבונדענע:' }
  };
  const labels = FIELD_LABELS[lang] || FIELD_LABELS['en'];
  document.querySelectorAll('[data-label]').forEach(el => {
    const key = el.dataset.label;
    if (labels[key]) el.textContent = labels[key];
  });

  document.documentElement.lang = lang;
}

(function initLang() {
  document.body.classList.add('lang-js');
  const plBtn = document.querySelector('.lang-btn.active');
  if (plBtn) switchLang('pl', plBtn);
})();'''


